"""
MKT Context — Luke chapters 19–20 (95 total verses; 19:1 already present)
Output: data/commentary/mkt-context/luke.json
Run: python3 scripts/zc-context-luke-19-20.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH19_20 = {
"19": {
"1": "<p>Jericho was a wealthy oasis city in the Jordan Valley, famous for balsam groves and date palms — luxury exports that made it a major commercial hub. As a customs point on the road from Peraea (east of the Jordan) to Jerusalem, it was an ideal location for a chief tax collector's operation. The Herodian winter palace complex was nearby, making Jericho a city of extreme wealth alongside extreme poverty.</p>",
"2": "<p>Zacchaeus as chief tax collector (architelōnēs — unique NT title suggesting he was the head tax contractor for the district) would have managed a network of subordinate collectors. Jericho's position on the main trade route from the Jordan ford made it extremely lucrative — balsam exports, date palm trade, and transit taxes from Peraea. His wealth (v.2 'he was rich') is consistent with controlling such a profitable collection point. Tax collectors were despised in Jewish society both for collaboration with Rome and for common fraud (cf. John 2:13-16 on temple money-changers).</p>",
"3": "<p>Zacchaeus's desire to see who Jesus was (tis estin houtos) uses an indirect question implying curiosity about identity — not merely about seeing the physical person. The crowd obstacle functions thematically: the very community that benefits from his tax system now physically blocks his access to Jesus. His short stature (mikros tē hēlikia) created a practical problem in the dense crowd typical of first-century Jericho's commercial districts. The detail is realistic rather than merely literary.</p>",
"4": "<p>The sycamore-fig tree (sykomorea — Ficus sycomorus, different from the western sycamore) was common in the Jericho valley — a spreading tree with low horizontal branches easily climbed. It was known as food for the poor (Amos 7:14, where Amos tends sycamore-figs) and was associated with humble origins. A wealthy architelōnēs climbing a tree in public — abandoning all dignity — was a comic scene for any Mediterranean observer. The honor-shame violation (a rich man climbing a tree to see a passing teacher) underlines the desperation of his desire.</p>",
"5": "<p>'Zacchaeus, hurry and come down, for I must stay at your house today' — the divine necessity (dei) governing Jesus's choice of Zacchaeus's house is the same word governing the passion (9:22) and Jerusalem destination (13:33). The 'must' is theological: this is the divine itinerary. The invitation to stay (meinai — the abiding/dwelling word used also in John's Gospel for covenantal relationship) in a tax collector's house violated Pharisaic purity norms about table fellowship with sinners (cf. 7:34 — 'friend of tax collectors and sinners').</p>",
"6": "<p>'He hurried and came down and received him joyfully' (chaírōn) — the joy-word (chairō) is a signal of kingdom reception in Luke: the same root appears in the Annunciation (1:14), the angel's proclamation (2:10), the disciples' return (10:17), and the prodigal son's reception (15:32). Zacchaeus's joy at receiving Jesus characterizes him as the 'good soil' of the sower parable (8:13). The speed of response ('hurried') mirrors the urgency of the divine invitation.</p>",
"7": "<p>'When they saw it, they all grumbled' (diagongyzō — the same verb used for Israel's wilderness murmuring against God in the LXX: Exod 16:7-8; Num 11:1; 14:2) — Luke's use of the exodus-murmuring verb for the crowd's reaction to Jesus's table-fellowship choices is deliberate. The crowd's complaint that 'he has gone in to be the guest of a man who is a sinner' (hamartōlos) reflects the Pharisaic table-fellowship purity code: shared meals marked community boundaries, and eating with sinners contaminated the righteous.</p>",
"8": "<p>'And Zacchaeus stood and said to the Lord, Behold, Lord, half of my goods I give to the poor; and if I have defrauded anyone of anything, I restore it fourfold' — whether this statement is a current practice (present tense 'I give') or a new resolve is debated. The fourfold restitution (tetraplas) exceeds legal requirement: Mosaic law required 120% restitution for fraud (Lev 6:5; Num 5:7) and fourfold only for stolen and slaughtered animals (Exod 22:1). Zacchaeus's voluntary fourfold exceeds even the highest biblical penalty — an act of exceeding generosity rather than minimal compliance.</p>",
"9": "<p>'Today salvation has come to this house, since he also is a son of Abraham' — the 'today' (sēmeron) of salvation echoes the Nazareth proclamation (4:21 — 'Today this scripture is fulfilled') and the promise to the dying criminal (23:43 — 'Today you will be with me in paradise'). Today is the Lukan eschatological 'now' of kingdom arrival. 'Son of Abraham' (huios Abraam) reinstates Zacchaeus into the covenant community from which his tax-collecting had effectively expelled him — and affirms that Israel's children include the lost ones Jesus seeks.</p>",
"10": "<p>'For the Son of Man came to seek and to save the lost' — this mission-statement summary (unique Lukan conclusion to the Zacchaeus pericope) functions as the programmatic statement of Luke's entire narrative. 'Lost' (apolōlos) echoes Luke 15's three parables: lost sheep, lost coin, lost son. The Son of Man language draws on Dan 7:13 while the seeking-and-saving mission redefines the Danielic figure's role: not military conquest but restoration of the scattered. The verse is Luke's clearest statement of what his Gospel is fundamentally about.</p>",
"11": "<p>'Because he was near Jerusalem and because they supposed that the kingdom of God was to appear immediately' — Luke's editorial introduction to the parable of the minas explains its purpose: correcting the disciples' imminent-kingdom expectation. The proximity to Jerusalem (the center of messianic expectation) and the preceding salvation events would naturally intensify hopes of an imminent Davidic restoration. The parable reframes kingdom arrival: there will be a delay (the nobleman goes to a far country), a period of faithful stewardship, and only then the kingdom's full expression.</p>",
"12": "<p>The parable of the minas (parallel to Matthew's talents, but differently structured) reflects specific historical context: Herod Archelaus's journey to Rome after Herod the Great's death (4 BCE) to receive confirmation of his kingship (Josephus, Ant. 17.208-239; War 2.14-38). A Jewish delegation also traveled to Rome to oppose his appointment (Josephus, Ant. 17.299-303). The parable's framework — a nobleman going to a far country to receive a kingdom while his citizens send an embassy opposing him — maps directly onto the Archelaus episode, familiar to any Palestinian hearer.</p>",
"13": "<p>'Calling ten of his servants, he gave them ten minas, and said to them, Engage in business until I come' (pragmateuomai — conduct business/trade). The mina (maneh/mnā) was approximately 3 months' wages (100 drachmas). Each servant receives equal capital — unlike Matthew's talent parable where capital is distributed proportionally. The equal initial distribution emphasizes that the difference in outcome reflects the servants' faithfulness, not differences in initial endowment. 'Until I come' (eos erchomai) frames the delay explicitly as a waiting period for the master's return.</p>",
"14": "<p>'But his citizens hated him and sent a delegation after him, saying, We do not want this man to reign over us' — the embassy of opposition reflects the historical delegation of Jews to Rome to oppose Archelaus (Josephus, Ant. 17.299-303). In Luke's allegorical framing, the 'citizens' who reject the nobleman represent those in Israel who reject Jesus's kingship. The explicit statement 'we do not want this man to reign over us' (ou thelomen touton basileusai eph' hēmas) anticipates the Jerusalem leadership's rejection and crucifixion of Jesus as the climax of this rejection.</p>",
"15": "<p>The returned king's 'having received the kingdom' (labonta tēn basileian) marks the transition between the delay period and the accounting. The three servants' reports (vv.16-24) follow the convention of stewardship accounting before a returning master — a recognized Greco-Roman administrative procedure described in papyri and reflected in Jesus's many steward-and-master parables. The 'what they had gained by doing business' (ti diepragmateusanto) asks specifically about productive activity, not just about preserving the initial capital.</p>",
"16": "<p>The first servant's tenfold return (ten minas from one) represents extraordinary commercial success — a 1000% return in the period of the master's absence. In first-century Mediterranean commerce, this would require aggressive trading rather than passive investment: money-lending, commodity trading, or tax-farming. The enthusiastic 'Lord, your mina has made ten minas more' attributes the gain to the mina itself (your mina, not 'I made') — a humble acknowledgment that the capital was the master's provision, not the servant's own means.</p>",
"17": "<p>'Well done, good servant! Because you have been faithful in a very little, you shall have authority over ten cities' — the reward-structure (authority over cities proportional to minas gained) reflects the administrative structure of Herodian Palestine where district governorships were the tangible expression of royal authority. The eschatological reward is responsibility and authority proportional to demonstrated faithfulness — the kingdom's reward is more kingdom-work, not retirement. This reflects a Jewish theology of reward as expanded service rather than passive enjoyment.</p>",
"18": "<p>The second servant's fivefold return (five minas from one) receives a proportional reward (authority over five cities). The exact proportionality — 10 minas = 10 cities, 5 minas = 5 cities — signals that kingdom reward is calibrated to faithfulness, not to absolute results. The servant who produces less is not penalized but also receives proportionally less — confirming that the distribution of authority in the kingdom is fair and calibrated, not arbitrary or uniform.</p>",
"19": "<p>'And he said to him, And you are to be over five cities' — the terse response (no verbal praise as in v.17's 'well done, good servant') may be significant: the second servant receives proportional reward but slightly less affirmation than the first. Some commentators argue this reflects a hierarchy of commendation. Whatever the interpretation, the basic principle remains: faithful stewardship of received resources is rewarded with expanded responsibility, and the reward-scale reflects the faithfulness-scale.</p>",
"20": "<p>The third servant's report ('Lord, here is your mina, which I kept laid away in a handkerchief') reflects a recognized ancient practice: concealing valuable items in cloth wrappings buried or hidden for security. The Mishnah discusses liability for deposited items: wrapping something in a cloth was less secure than digging and burying it (m. Bava Metzia 3.10-11 — a depositor who wraps money in a cloth is liable for losses; one who buries it is not). The servant's method was actually suboptimal even by the standards of cautious storage.</p>",
"21": "<p>'I was afraid of you, because you are a severe man. You take what you did not deposit, and reap what you did not sow' — the servant's explanation reveals his character: fear (phoboumai) rather than faith drove his inaction. The accusation against the master ('severe man, taking what you did not deposit, reaping what you did not sow') echoes ancient agricultural exploitation complaints — absentee landlords extracting produce from tenant farmers was a recognized injustice in first-century Galilee. The servant frames his master in oppressive terms, justifying his own passivity through the master's character.</p>",
"22": "<p>'I will condemn you with your own words, you wicked servant!' — the master's response uses the servant's own characterization against him: if you genuinely believed I was severe and extractive, that belief should have motivated even greater effort (at minimum, bank deposit for interest). The argument is ad hominem but logically coherent: the servant's stated premise (master is harsh) and his actual behavior (passive concealment) are inconsistent. He cannot use fear of the master's severity to justify exactly the behavior the severe master will punish most harshly.</p>",
"23": "<p>'Why then did you not put my money in the bank, and at my coming I might have collected it with interest?' — lending money at interest (trapeza — literally 'table' of the money-changer/banker) was a recognized financial instrument in the Greco-Roman world. Jewish law prohibited interest on loans to fellow Jews (Exod 22:25; Lev 25:37; Deut 23:19-20) but permitted it on loans to Gentiles. The master's suggestion of bank deposit represents the minimal acceptable form of productive stewardship — even passive interest-bearing was better than total inactivity.</p>",
"24": "<p>'Take the mina from him, and give it to the one who has the ten minas' — the redistribution of the inactive servant's mina to the most productive servant follows the economic logic of productive deployment: capital should go where it will be used. The crowd's protest ('Lord, he has ten minas!') acknowledges the seeming unfairness but misses the parable's point: the mina is not reward for the first servant's past performance but capital for ongoing productive deployment. Kingdom resources follow productive faithfulness.</p>",
"25": "<p>'And they said to him, Lord, he has ten minas!' — this parenthetical crowd-protest (unique to Luke's version, absent from Matthew's parallel) creates a narrative pause that Jesus explicitly addresses in v.26's principle. The protest voice represents a fairness-calculation that sees the redistribution as inequitable: the already-successful servant receives more while the unsuccessful servant loses what little he had. The protest sets up the counter-intuitive principle that follows.</p>",
"26": "<p>'I tell you that to everyone who has, more will be given; but from the one who has not, even what he has will be taken away' — this principle (also appearing in Luke 8:18 after the sower parable) uses economic observation to describe spiritual-kingdom dynamics. In Greco-Roman patronage systems, those who had demonstrated effective use of patron resources received more; those who had not were cut off from the patronage relationship. Applied to kingdom reception: faithful responsiveness to the word generates more; passive or fearful non-use loses even the initial gift.</p>",
"27": "<p>'But as for these enemies of mine, who did not want me to reign over them, bring them here and slaughter them before me' — the execution of the rebellious citizens (those who sent the opposing embassy, v.14) reflects the historical reality of what happened to rebellious subjects in ancient Near Eastern kingdoms and indeed to those who opposed Archelaus (he killed hundreds in the temple courts, Josephus Ant. 17.206-218). In Luke's allegorical framing, this verse points to the judgment that falls on Jerusalem for rejecting Jesus — the 70 CE destruction being Luke's readers' recent memory.</p>",
"28": "<p>'And when he had said these things, he went on ahead, going up to Jerusalem' — the travel notice resumes the Jerusalem journey (begun 9:51) in its final stage. 'Going up' (anabainōn) is the proper geographical term: Jerusalem sits at approximately 2,500 feet elevation; Jericho where they were is 850 feet below sea level — a 3,300-foot ascent over about 17 miles. The physical ascent maps onto the theological ascent: Jerusalem is the place of the passion, and going up to it is going up to the confrontation Jesus has been moving toward throughout the travel narrative.</p>",
"29": "<p>Bethphage and Bethany were villages on the slopes of the Mount of Olives east of Jerusalem. Bethany (modern al-Eizariya) is identified with the home of Mary, Martha, and Lazarus (John 11:1). Bethphage ('house of unripe figs') is less certainly located but was understood to be the last inhabited place before Jerusalem on the Jericho road. The Mount of Olives (Har ha-Zeitim) carried significant eschatological weight in Jewish tradition: Zechariah 14:4 places the divine theophany of the day of the LORD on the Mount of Olives.</p>",
"30": "<p>The instruction to find 'a colt on which no one has ever yet sat' — the unridden colt reflects Jewish and ancient Near Eastern tradition that animals designated for sacred purposes must be unused by ordinary tasks (Num 19:2 — the red heifer never yoked; 1 Sam 6:7 — the cart animals never yoked; 2 Sam 6:3 — the new cart). The unridden animal marks the procession as ritually significant — this is not ordinary transportation but ceremonially appropriate conveyance for a royal entry.</p>",
"31": "<p>'If anyone asks you, Why are you untying it? You shall say this: The Lord needs it' — the advance knowledge of the colt's availability and the scripted response suggests either divine foreknowledge or prior arrangement (a pre-arranged signal). 'The Lord needs it' (ho kyrios autou chreian echei) uses kyrios without the article in some manuscripts — 'the Lord' or 'its master' — an ambiguity that may be deliberate. The disciples' authority to claim the animal 'in the Lord's name' reflects the cultural protocol where a person of recognized authority could requisition hospitality resources.</p>",
"32": "<p>The disciples' finding 'just as he had told them' (kathōs eipen autois) is a Lukan fulfillment-formula for prophetic foreknowledge — Jesus's prediction exactly matches reality. The same formula appears at the preparation of the Passover room (22:13). Luke uses these exact-prediction fulfillments to establish Jesus's prophetic authority: his knowledge of specific details before they occur validates his larger prophetic role. The colt found precisely as predicted is part of the divine script being executed.</p>",
"33": "<p>'As they were untying the colt, its owners said to them, Why are you untying the colt?' — the owners' challenge is the situation Jesus anticipated. The word 'owners' (hoi kyrioi autou — literally 'its lords/masters') uses the same word (kyrios) that Jesus had used for himself in v.31 ('the Lord needs it'). Luke may intend a wordplay: the owners (lords) of the colt yield to the Lord who needs it. The transaction reflects the ancient hospitality convention where wealthy owners made transport animals available to recognized community figures.</p>",
"34": "<p>'The Lord needs it' — the disciples' response exactly replicates the scripted answer from v.31. The response apparently satisfies the owners' concern immediately — either because they recognized the authority behind the title, or because this was a pre-arranged signal (a form of password). The seamless fulfillment of Jesus's prediction about the owners' response confirms the divine orchestration of the entry. Whatever the mechanism, the narrative presents Jesus as foreknowing and sovereign over the entry's logistical details.</p>",
"35": "<p>The disciples' throwing of their garments on the colt (for Jesus to ride) and on the road before him echoes 2 Kings 9:13, where the people threw their garments on the steps before newly anointed King Jehu ('each of them quickly took his garment and put it under him on the bare steps, and they blew the trumpet and proclaimed, Jehu is king'). The conscious parallel to the Jehu anointing scene — an impromptu royal acclamation using thrown garments — frames the entry as a royal proclamation, not merely a procession.</p>",
"36": "<p>The throwing of garments on the road before Jesus also echoes the Elisha-Elijah mantle tradition (2 Kgs 2:8, 13-14) and the royal road-preparation conventions of the ancient Near East, where roads were cleared and covered for royal processions. Josephus describes similar garment-throwing for Agrippa (Ant. 19.294). The gesture combines royal acclamation and prophetic succession imagery — both of which have been applied to Jesus throughout Luke's narrative (1:76-77; 3:4-6; 4:18; 7:22-23).</p>",
"37": "<p>'The whole multitude of his disciples began to rejoice and praise God with a loud voice for all the mighty works they had seen' — Luke's emphasis on 'disciples' (mathētōn) rather than 'the crowds' (Mark/Matthew) and on their specific motivation ('for all the mighty works they had seen') gives the acclamation an eyewitness character. The joy (chairō) marks this as a kingdom moment — the same joy-vocabulary pervading Luke's Gospel at kingdom-arrival moments. The works they have witnessed (healings, exorcisms, resurrections) form the evidentiary basis for their acclamation.</p>",
"38": "<p>'Blessed is the King who comes in the name of the Lord! Peace in heaven and glory in the highest!' — the acclamation combines Ps 118:26 ('Blessed is he who comes in the name of the LORD') with an explicit royal interpretation: Luke alone adds 'the King' (ho basileus) where other Gospels simply quote the Psalm. The second line echoes the angels' song at the birth (2:14 — 'Glory to God in the highest, and on earth peace among those with whom he is pleased'), creating a narrative inclusio. At the birth, peace was announced on earth; at the entry, peace is proclaimed in heaven — the full cosmic scope of the kingdom's arrival.</p>",
"39": "<p>'Teacher, rebuke your disciples' — the Pharisees' objection to the acclamation focuses on silencing the disciples' praise. Their address 'Teacher' (Didaskale) is respectful but not confessional — they do not share the disciples' kingdom-recognition. The rebuke-request reflects the Pharisaic concern about political provocation: a royal acclamation of Jesus entering Jerusalem during Passover could trigger Roman military response. The crowds were enormous at Passover (Josephus estimates 2-3 million; more conservative estimates 100,000-200,000), making any messianic demonstration politically dangerous.</p>",
"40": "<p>'I tell you, if these were silent, the very stones would cry out' — the stone-crying-out saying is unparalleled in Jewish tradition, though it echoes prophetic texts where the created order responds to divine action (Hab 2:11 — 'the stone will cry out from the wall'; Isa 55:12 — 'the trees of the field shall clap their hands'). The hyperbolic statement expresses the inevitability of this moment: what is happening cannot be suppressed — if human voices are silenced, the creation itself would supply the missing praise. The entry of the King is cosmically significant, not merely politically contingent.</p>",
"41": "<p>'And when he drew near and saw the city, he wept over it' (eklausen) — Luke alone records Jesus's weeping over Jerusalem at the entry (a second weeping in 19:41-44; see also 22:42 and the Lament of ch 13). The Greek klaiō (wept, cf. John 11:35 for Lazarus) denotes loud weeping rather than quiet tears (dakryō). The posture of a teacher weeping over a city corresponds to the prophetic lament tradition: Jeremiah wept over Jerusalem's coming destruction (Jer 9:1; 13:17; Lam 1:2, 16). Jesus inhabits the prophetic role of the weeping prophet.</p>",
"42": "<p>'Would that you, even you, had known on this day the things that make for peace!' (ta pros eirēnēn) — the peace-cry echoes the disciples' acclamation ('Peace in heaven,' v.38) but applies it as an unmet conditional: Jerusalem could have had the peace it was named for (Yeru-shalem = 'city/foundation of peace') but failed to recognize it. The historical irony is thick: the city of peace fails to recognize the Prince of Peace. 'On this day' (en tē hēmera tautē) emphasizes the specific moment of opportunity — this entry, this day — that Jerusalem was missing.</p>",
"43": "<p>'For the days will come upon you, when your enemies will set up a barricade around you and surround you and hem you in on every side' — the siege prophecy maps precisely onto the Roman siege of Jerusalem in 70 CE. Josephus (War 5.6.2) describes the circumvallation wall (charax) built by Titus — a massive earthwork barrier surrounding the city to prevent escape. The specific detail of the charax (rampart/siege-wall) corresponds to the technical Roman military engineering Jesus predicts. This precision has led some to see it as vaticinium ex eventu (prophecy after the fact) but Luke's narrative presents it as Jesus's genuine prediction.</p>",
"44": "<p>'They will tear you down to the ground, you and your children within you. And they will not leave one stone upon another in you, because you did not know the time of your visitation' — the destruction of Jerusalem including its walls (Josephus, War 7.1.1 — Titus ordered the entire city and temple razed except for three towers) is connected to the theological cause: 'you did not know the time of your visitation' (ton kairon tēs episkopēs sou). The 'visitation' (episkopē) echoes 1:68 ('God has visited and redeemed his people') — the same divine visitation motif. Jerusalem's destruction results from failing to recognize God's salvific visitation in Jesus.</p>",
"45": "<p>The temple cleansing in Luke (parallel Mark 11:15-17; Matt 21:12-13; John 2:13-22) is compressed relative to the other Gospels — Luke omits the money-changers, the dove-sellers, and the overturned tables, giving only the expulsion of the sellers. The temple mount (Hieron — the entire temple complex, not just the naos/sanctuary) contained the Court of the Gentiles where trading occurred, separated from the sanctuary proper. The marketplace (emporion) in the Court of the Gentiles served Passover pilgrims needing currency exchange (Tyrian silver for temple tax) and sacrificial animals (doves for purification offerings).</p>",
"46": "<p>'It is written, My house shall be a house of prayer, but you have made it a den of robbers' — the two OT citations (Isa 56:7 and Jer 7:11) carry specific weights. Isaiah 56:7 emphasizes universal inclusion ('My house shall be called a house of prayer for all nations' — Luke omits 'for all nations,' present in Mark) — the temple's proper function. Jeremiah 7:11's 'den of robbers' was Jeremiah's indictment of the temple in the face of coming destruction — used during the period immediately before the Babylonian siege. Jesus applies the Jeremiah citation to the current temple establishment, implying a parallel judgment is coming.</p>",
"47": "<p>'And he was teaching daily in the temple' — the daily teaching in the temple during the Passover week (Luke 19:47-21:38 is structured as consecutive days in the temple) reflects the reality that pilgrims gathered in the temple courts for teaching during festival seasons. Rabbis taught in the porticoes (stoas) of the outer courts. The temple as educational venue was well established: m. Sanhedrin 11.2 locates the high court in the temple; Josephus describes philosophers debating in the porticoes (Ant. 17.149-167). Jesus's daily teaching in the temple is presented as his rightful activity in his Father's house (2:49).</p>",
"48": "<p>'But they did not find anything they could do, for all the people were hanging on his words' — the leadership's inability to act against Jesus despite their desire to destroy him is explained by the crowd's intense reception (exekremato — literally 'hung upon,' the word for rapt attention). The political calculation was that public action against Jesus during Passover when Jerusalem was packed with pilgrims from all over the world was too dangerous (cf. 22:2 — 'they feared the people'). The crowd functions as a de facto protection for Jesus until the betrayal arrangement circumvents the crowd problem.</p>"
},
"20": {
"1": "<p>The setting 'one day as he was teaching in the temple and preaching the gospel' (euangelizomenou) establishes the context for the authority-challenge: Jesus is engaged in prophetic-messianic activity (gospel proclamation in the temple) that provocatively implies authority over the sacred space he has just cleansed. The chief priests, scribes, and elders form the Sanhedrin's three constituent groups — the governing body (71 members) that held jurisdiction over religious matters in Jerusalem. Their challenge about authority is both a legal and theological inquiry.</p>",
"2": "<p>'Tell us by what authority you do these things, or who it is that gave you this authority?' — the two questions ('by what authority?' and 'who gave it?') address the two possible grounds of authority in Jewish religious life: the authority itself (divine commission? prophetic call? rabbinic ordination?) and its source (who authorized you?). Rabbis derived authority through ordination chains traceable to Moses; prophets derived it directly from divine commission. Jesus's cleansing of the temple without Sanhedrin authorization was an actionable usurpation of institutional authority.</p>",
"3": "<p>Jesus's counter-question about John's baptism is not evasion but a genuine test of the questioners' capacity for honest inquiry. In Jewish legal tradition, answering a question with a question was recognized pedagogical technique — forcing the questioner to examine their own presuppositions before the answer would be useful. The specific counter-question about John places the Sanhedrin's authority claim in a bind: they must either affirm divine authority (and thereby establish the principle that validates Jesus's own authority) or deny it (and lose popular standing).</p>",
"4": "<p>'Was the baptism of John from heaven or from man?' — the binary of 'from heaven' (ex ouranou — a Jewish circumlocution for 'from God') or 'from men' represents the exhaustive division of religious authority claims. John's movement was publicly recognized as prophetic (7:26-28 — 'more than a prophet'); his murder by Herod Antipas had made him a popular martyr figure (9:7-9). The Sanhedrin's inability to evaluate John's authority honestly reveals their epistemological problem: their judgments are governed by political calculation rather than genuine inquiry into truth.</p>",
"5": "<p>The Sanhedrin's internal deliberation ('If we say, From heaven, he will say, Why did you not believe him?') is exposed by Luke's narrative — the reader sees the cynical political calculation. They don't discuss what is true but what is advantageous to say. This is the hypocrisy Jesus has been warning against throughout the journey narrative (12:1; 13:15; 15:2; 16:14-15). Their deliberation reveals that their objection to Jesus is not theological (they can't honestly evaluate authority claims) but political (they will not risk their social position).</p>",
"6": "<p>'But if we say, From men, all the people will stone us, for they are convinced that John was a prophet' — the threat of stoning for denying John's prophetic status reflects the crowd's intense veneration of John as a martyr-prophet. Stoning was the legal penalty for blasphemy against a prophet (Deut 13:5; 18:20) and for leading Israel astray. The Sanhedrin's fear of being stoned by the crowd inverts the normal power dynamic: the supreme court fears the mob, which fears no retribution in defending the popular prophet's honor. The crowd's theological convictions create a political constraint on the ruling body.</p>",
"7": "<p>'So they answered that they did not know where it came from' — the formal ignorance-claim ('we do not know') is dishonest by the narrative's own witness (vv.5-6 showed they do have views but won't state them). Their strategic ignorance-claim dissolves the authority-challenge: if they cannot adjudicate John's authority, they lack the epistemic standing to adjudicate Jesus's authority. The counter-question has exposed their incapacity for honest theological judgment and nullified their standing to challenge anyone else's authority claims.</p>",
"8": "<p>'Neither will I tell you by what authority I do these things' — Jesus's refusal matches their own refusal: mutual non-disclosure ends the exchange in a logical impasse. But the impasse is asymmetrical: they cannot answer because they won't; Jesus will not answer because the conditions for honest dialogue (good-faith inquiry) are absent. The outcome is that Jesus has publicly exposed the Sanhedrin's bad faith without being trapped by a direct authority-claim that they could use against him.</p>",
"9": "<p>The parable of the wicked tenants (parallel Mark 12:1-12; Matt 21:33-46) opens with vineyard imagery immediately recognizable as Israel from Isaiah's Song of the Vineyard (Isa 5:1-7 — 'For the vineyard of the LORD of hosts is the house of Israel'). The audience (the leaders challenging Jesus, v.1) would have recognized the vineyard allegory immediately. The detailed vineyard description (Mark's version includes the hedge, winepress, and tower from Isa 5:2) is abbreviated in Luke — Luke's audience probably knew the Isaiah source well enough for sparse allusion.</p>",
"10": "<p>The repeated servant-sending pattern (servant-servant-servant/son) reflects the prophetic history of Israel: God sent prophets repeatedly to receive the covenant's 'fruit' (justice, righteousness) and was repeatedly rejected. The beating and shameful treatment of the servants echoes the Deuteronomic History's account of prophet-rejection: Elijah fleeing (1 Kgs 19), Jeremiah beaten and imprisoned (Jer 20:2; 37:15), Isaiah's tradition (the Suffering Servant), and later tradition about prophets being killed (Matt 23:37; Acts 7:52; Heb 11:36-38). The parable compresses centuries of prophetic history.</p>",
"11": "<p>The second servant's treatment ('they also beat and treated shamefully and sent away empty-handed') follows the same pattern as the first. The repetition establishes a pattern of escalating rejection. In Palestinian tenant-farming practice, if a landlord's agent was repeatedly refused and abused, the legal options were limited: court action was slow and uncertain in the Roman period; direct confrontation with entrenched tenants was dangerous. The owner's continued sending of agents (rather than immediate force) reflects the parable's portrayal of divine patience exhausted by repeated rejection.</p>",
"12": "<p>The third servant's wounding and ejection (traumatisantes, the same verb for Jesus's being wounded in his passion, Luke 22:63-65; cf. Isa 53:5 LXX — traumatizō) prepares the transition to the son's death. The three servants (some manuscripts have more in Mark/Matthew) represent the prophetic series culminating in the decisive sending of the Son. The escalating violence against each servant (beaten → treated shamefully → wounded and cast out) mirrors the escalating rejection of God's covenant claims on Israel over its history.</p>",
"13": "<p>'What shall I do? I will send my beloved son; perhaps they will respect him' — the vineyard owner's deliberation is rendered explicitly in Luke's version, giving him an interior voice. 'My beloved son' (ton huion mou ton agapēton) uses the same phrase as the baptismal voice ('my beloved Son,' 3:22) and the Transfiguration voice ('my chosen Son,' 9:35). The parable's transparency about the son's identity is high — any hearer following Luke's Gospel recognizes the beloved son as Jesus. 'Perhaps they will respect him' (isos autou entraphēsontai) expresses hope that the ultimate communication will succeed where all previous ones failed.</p>",
"14": "<p>'But when the tenants saw him, they said to themselves, This is the heir. Let us kill him, so that the inheritance may ours' — the tenants' reasoning about killing the heir to claim the inheritance reflects a specific legal situation: if an absentee landlord died without heirs, tenants might claim the land through adverse possession (m. Bava Batra 3.3 on unclaimed property). Their deliberation ('let us kill him that the inheritance may be ours') exposes the logic of Jesus's rejection: the Jerusalem leadership kills Jesus not in ignorance but in deliberate self-interest — to preserve their own authority and position.</p>",
"15": "<p>'So they threw him out of the vineyard and killed him' — the reversal of the order in Mark (kill first, then throw out) to Luke's order (throw out first, then kill) may reflect the historical sequence of Jesus's passion: expelled from Jerusalem (the vineyard) before crucifixion outside the city walls (Heb 13:12-13 — 'Jesus also suffered outside the gate'). Luke's sequence maps more precisely onto the actual geography of Jesus's death. 'What then will the owner of the vineyard do to them?' — the question (rhetorical in Matthew/Mark) invites the audience's own verdict before Jesus delivers it.</p>",
"16": "<p>'He will come and destroy those tenants and give the vineyard to others' — the judgment on the tenants (destruction) and transfer of the vineyard ('to others') is Luke's version of the parabolic judgment that points toward both the Jerusalem leadership's destruction (70 CE) and the Gentile mission (Acts). 'When they heard this, they said, Surely not!' (mē genoito — the strongest Greek negative optative, 'may it never be!') is the audience's shocked protest — the leaders recognize that the parable is about them and recoil from its conclusion. The protest is both a character-reveal and confirmation that they understood the parable perfectly.</p>",
"17": "<p>'But he looked directly at them and said, What then is this that is written: The stone that the builders rejected has become the cornerstone?' — the Psalm 118:22 citation (LXX — ho lithos hon apedokimasan hoi oikodomountes, houtos egenēthē eis kephalēn gōnias) recycles the Hallel Psalm already echoed in the entry acclamation (118:26, 'Blessed is he who comes'). The rejected-stone-becoming-cornerstone (or capstone) reversal follows the Lukan reversal-theology: the humble exalted, the last first, the rejected vindicated. The 'builders' who reject the stone are the Jerusalem leadership who have just heard themselves condemned in the parable.</p>",
"18": "<p>'Everyone who falls on that stone will be broken to pieces, and when it falls on anyone, it will crush him' — the stone-saying adds two outcomes to the Psalm citation. The two stone-images draw on different OT texts: falling on the stone (Isa 8:14-15 — the LORD as a stone of stumbling and a rock of offense, over which Israel stumbles and is broken) and the stone falling/crushing (Dan 2:34-35, 44-45 — the stone cut without hands that crushes the statue representing world empires). Together the two images create a double stone-judgment: stumbling against Jesus results in broken pieces; Jesus's final coming crushes all opposition.</p>",
"19": "<p>'The scribes and chief priests sought to lay hands on him at that very hour, for they perceived that he had told this parable against them, but they feared the people' — the leaders' correct interpretation of the parable against themselves confirms Luke's earlier point (v.14 — the tenants knew exactly what they were doing). Their immediate desire to arrest Jesus collides again with the crowd constraint (cf. 19:48 — the people hanging on his words). The political calculation that has governed their inaction throughout the temple week continues: public action against Jesus requires a crowd-circumventing strategy, which Judas will provide (22:3-6).</p>",
"20": "<p>'So they watched him and sent spies, who pretended to be sincere, that they might catch him in something he said, so as to deliver him up to the authority and jurisdiction of the governor' — the spy-mission reveals the strategy: since direct action was impossible, trap Jesus in a statement that Rome would act on. The specifically Roman legal route ('deliver to the authority of the governor') identifies the target charge: something Rome would prosecute (rebellion, tax evasion, royal pretension). The 'sincere' (dikaioi — literally 'just men') pretense is the same hypocrisy Jesus has repeatedly denounced in the journey narrative.</p>",
"21": "<p>'Teacher, we know that you speak and teach rightly, and show no partiality, but truly teach the way of God' — the flattering introduction is transparent manipulation but contains accurate theological description: Jesus does not accept prosōpolēmpsia (face-receiving, partiality based on social status) — a consistent Lukan theme (cf. Acts 10:34). The spies' accurate description of Jesus's impartiality creates the rhetorical setup for the trap: if you are truly impartial, you cannot hedge on the tax question based on political considerations.</p>",
"22": "<p>'Is it lawful for us to give tribute to Caesar, or not?' — the question (phoros — poll tax, the personal tribute paid to Rome) was one of the most politically charged questions in first-century Judea. The Zealot movement (founded by Judas the Galilean, 6 CE) explicitly rejected the census and poll tax as incompatible with God's sovereignty over Israel (Josephus, Ant. 18.4-10). The Pharisees (who valued compliance with Torah over political resistance) were generally more accommodating. Any answer creates a problem: 'yes' offends Jewish nationalists; 'no' constitutes sedition before Roman law.</p>",
"23": "<p>'But he perceived their craftiness' (panourgia — cunning/craftiness, used in the LXX for the serpent of Gen 3:1 and in 2 Cor 11:3 for Satan's deception of Eve) — Luke identifies the spies' technique with the language of Satanic deception. The term situates the trap within the cosmic conflict between Jesus and the adversary (cf. 4:1-13 where the devil tempts Jesus; 22:3 where Satan enters Judas). The trap is not merely a political maneuver but part of the cosmic adversarial campaign against Jesus throughout Luke's narrative.</p>",
"24": "<p>'Show me a denarius. Whose likeness and inscription does it have?' — the request for a denarius brings a Roman silver coin into the temple context. The denarius bore the image of the current emperor (Tiberius in Jesus's time) with the Latin inscription 'Ti[berius] Caesar Divi Aug[usti] F[ilius] Augustus' (Tiberius Caesar, Son of the Divine Augustus) — a coin that claimed both imperial authority and quasi-divine status for the emperor. That someone in the crowd immediately produces such a coin is itself significant: Roman coins circulating in the temple complex.</p>",
"25": "<p>'Then render to Caesar the things that are Caesar's, and to God the things that are God's' — the answer is neither sedition nor Roman collaboration but a sophisticated two-kingdom distinction. 'Render to Caesar' acknowledges that Caesar's image on the coin establishes his claim — if you use Caesar's currency, you participate in Caesar's economic system and can render tax. 'Render to God' asserts a separate and superior claim: what bears God's image (humanity, made in God's image, Gen 1:26-27) belongs to God. The answer outwits the trap by establishing a principled two-domain framework rather than picking either horn of the dilemma.</p>",
"26": "<p>'And they were not able in the presence of the people to catch him in what he said, but marveling at his answer they became silent' — the spies' failure is total: not only was the trap escaped, but the answer generated wonder (thaumasantes) even among those who came to entrap. The marveling-into-silence (esigēsan — they fell silent) is the characteristic response to defeat in ancient rhetorical combat. In honor-shame culture, public rhetorical victory was a significant social achievement; Jesus has won decisively before witnesses, further enhancing his public standing.</p>",
"27": "<p>The Sadducees' appearance at this point — they 'deny that there is a resurrection' (anastasis mē einai) — is confirmed by multiple ancient sources: Josephus (Ant. 18.16 — Sadducees say souls die with bodies), Acts 23:8 (Sadducees say there is no resurrection, angel, or spirit), and rabbinic traditions. The Sadducees accepted only the Torah's written text (Pentateuch) as binding, rejecting the Pharisaic oral tradition. Their resurrection-denial was based on the Torah's relative silence on personal resurrection and the Deuteronomy laws about levirate marriage, which they believed rendered resurrection internally inconsistent with Torah.</p>",
"28": "<p>The levirate marriage law (Deut 25:5-10 — a brother must marry his dead brother's childless widow to preserve the family line) was a longstanding Israelite institution also attested in Genesis 38 (Judah and Tamar). The Sadducees' question constructs a reductio ad absurdum scenario: seven brothers, one wife — whose wife at the resurrection? The scenario uses the multiplication of levirate marriages to show the absurdity (as they see it) of resurrection: the social institution of marriage, which Torah regulates, would be reduced to chaos by resurrection's requirement.</p>",
"29": "<p>The seven-brothers scenario (vv.29-32) is a philosophical thought experiment in the Jewish tradition of using extreme cases to test principles (a form of the rabbinic gezera shawa or kal wahomer argument pushed to its limit). Seven brothers sequentially marrying one woman and all dying without children is maximally improbable but logically possible. The scenario is designed to expose what the Sadducees see as the absurdity of resurrection belief when mapped onto Torah's social legislation. The number seven (the number of completeness) makes the case as comprehensive as possible.</p>",
"30": "<p>The second brother's marriage 'took the woman as wife' — the formulaic repetition through verses 29-32 creates a literary monotony that mirrors the Sadducees' philosophical point: seven iterations of the same institution, seven times the same result, seven different potential resurrection-claims. The repetition is rhetorically deliberate: by the time the seventh brother is reached, the absurdity has been maximized and the dilemma seems insoluble.</p>",
"31": "<p>The escalating repetition through the third, fourth, fifth, sixth, and seventh brothers is typically abbreviated in commentaries but serves the rhetorical purpose of the Sadducean argument: the problem compounds with each iteration. In the Sadducean framework, each successive marriage creates a new claim that cannot be adjudicated in a resurrection scenario without rendering Torah's levirate institution meaningless or absurd. Their point is that Torah's legislation presupposes the non-resurrection of the dead — resurrection would create legally insoluble conflicts within Torah's own framework.</p>",
"32": "<p>'Finally, the woman died too' — the woman's death closes the scenario and moves to the resurrection dilemma. The Sadducees have constructed a closed logical universe: seven legal marriages under Torah law, all parties deceased, all claims equally valid. 'In the resurrection, therefore, whose wife will the woman be?' Their question assumes that resurrection would simply reinstate the earthly social structure — the same marriages, the same property rights, the same family structures. Jesus's answer will challenge this assumption as the key logical error.</p>",
"33": "<p>'In the resurrection, therefore, whose wife will the woman be?' — the Sadducees' question assumes the continuity of earthly social institutions into the resurrection state. This assumption — that resurrection = resuscitation of earthly life — is the philosophical premise Jesus will refute. Jewish resurrection theology in the Pharisaic tradition (2 Macc 7; 1 Enoch 103-104; 4 Ezra 7:97; b. Sanhedrin 90b-91a) actually held a range of views on the continuity of earthly relationships in the resurrection, making Jesus's answer a contribution to an ongoing intra-Jewish debate.</p>",
"34": "<p>'The sons of this age marry and are given in marriage' — the distinction between 'this age' (ho aiōn houtos) and 'that age' (ho aiōn ekeinos) is a standard Jewish apocalyptic framework (Sifre Deut 32; b. Berakhot 34b; Mishnah Avot 4.17). This age is characterized by marriage (necessary for human reproduction and continuation); the age to come transcends this necessity. Jesus accepts the apocalyptic two-age framework and uses it to answer the Sadducees: they have confused this age's structures with that age's reality.</p>",
"35": "<p>'But those who are considered worthy to attain to that age and to the resurrection from the dead neither marry nor are given in marriage' — resurrection-life transcends the social institutions of this age. The Sadducean trap assumed resurrection would reinstantiate this age's marriage structure; Jesus denies this. The phrase 'considered worthy' (kataxiōthentes) introduces an element of divine judgment-at-resurrection that is consistent with Jewish apocalyptic but absent from the Sadducean (non-resurrection) framework. The resurrection state is qualitatively different, not merely a continuation.</p>",
"36": "<p>'For they cannot die anymore, because they are equal to angels and are sons of God, being sons of the resurrection' — the angel-comparison addresses the reproduction-necessity argument: marriage exists in this age for procreation (and thus for covenant community continuity). Angels, who cannot die, require neither reproduction nor the marriage institution that serves it. The resurrection-state's angelomorphic character (becoming 'equal to angels' — isangeloi, a term found only here in the NT) draws on Jewish traditions about righteous humans being elevated to angelic status at resurrection (1 Enoch 104:2-6; 2 Bar 51:5-10; T. Job 18.4).</p>",
"37": "<p>'But that the dead are raised, even Moses showed, in the passage about the bush, where he calls the Lord the God of Abraham and the God of Isaac and the God of Jacob' — the appeal to Exodus 3:6 (God's self-identification to Moses at the burning bush) is exegetically brilliant because it meets the Sadducees on their own ground: the Torah text (not the prophets or the writings). God's use of present tense ('I am the God of Abraham') in a text from centuries after the patriarchs' deaths implies their continued existence — past-tense 'I was the God of Abraham' would be more natural if they were simply dead.</p>",
"38": "<p>'Now he is not God of the dead, but of the living, for all live to him' — the theological principle that concludes the argument: God's covenantal relationship with the patriarchs cannot be merely historical (with the now-dead). God, who is the God of the living not the dead, must maintain living relationship with those in covenant with him — implying their continued existence. The phrase 'all live to him' (pantes gar autō zōsin) expresses the Jewish theological conviction that all people are alive before God's eternal perspective, even those who have died from the human temporal perspective.</p>",
"39": "<p>'Then some of the scribes answered, Teacher, you have spoken well' — the scribal approval of Jesus's answer in the resurrection debate is surprising: scribes were more aligned with Pharisaic than Sadducean theology, and thus would appreciate Jesus's argument for resurrection from Torah. The response 'you have spoken well' (kalōs eipas) is formal approval of a rhetorical and exegetical argument — the scribes award Jesus the dialectical victory over the Sadducees in this round of temple controversy. After this, no one dared ask him another question (v.40).</p>",
"40": "<p>'For they no longer dared to ask him any question' — the three-stage controversy sequence (authority challenge, Caesar question, resurrection question) has exhausted the Sanhedrin's ability to trap Jesus. Each attempt has resulted in Jesus's victory and the questioners' public humiliation or silence. The cessation of questioning marks the end of their active challenge strategy — they shift to the passive surveillance (v.20's spies) and will ultimately resort to betrayal (22:3-6) rather than further direct confrontation. Jesus's rhetorical dominance in the temple has been total.</p>",
"41": "<p>'But he said to them, How can they say that the Christ is David's son?' — having successfully defended himself against three challenges, Jesus now takes the offensive with his own question about the Messiah's identity. The Davidic descent of the Messiah was a standard expectation (Isa 11:1; Jer 23:5; Ezek 34:23; Pss. Sol. 17.21 — 'Raise up for them their king, the son of David'). Jesus's question does not deny the Davidic descent (cf. Luke 1:32-33, 69; 2:4; 18:38-39) but challenges the adequacy of understanding the Messiah only in Davidic-son terms.</p>",
"42": "<p>'For David himself says in the Book of Psalms, The Lord said to my Lord, Sit at my right hand' — Psalm 110:1 (LXX: eipen ho Kyrios tō Kyriō mou) was the most-cited OT text in early Christianity (Acts 2:34-35; 1 Cor 15:25; Heb 1:13; 10:13). Its attribution to David ('David himself says') makes the first 'Lord' (YHWH/God) speaking to a second 'Lord' (David's lord, the enthroned figure). David's son would normally be David's inferior — a son does not call his father 'my lord.' But David calls the messianic figure his lord, implying the Messiah transcends the father-son hierarchy.</p>",
"43": "<p>'Until I make your enemies your footstool' — the footstool-imagery (Ps 110:1b) reflects ancient Near Eastern royal iconography where conquered enemies were depicted prostrate under the victorious king's feet (Ps 8:6; Josh 10:24; 1 Kgs 5:3). The session 'at the right hand' (ek dexiōn mou) is the place of highest honor and authority in ancient Near Eastern court protocol — second only to the sovereign. The Psalm's promise to the enthroned figure is thus both a seat of honor and a guarantee of ultimate victory over all opposition.</p>",
"44": "<p>'David thus calls him Lord, so how is he his son?' — the question is a rhetorical puzzle (not a denial of Davidic descent) that forces hearers to reckon with the Messiah's identity beyond the merely human-royal category. The answer implicit in Luke's Gospel (and made explicit in Acts 2:36) is that Jesus is both David's son (by physical descent, 1:32) and David's Lord (by his resurrection and enthronement at God's right hand). The Davidic-son category is true but insufficient — the Messiah is simultaneously David's descendant and David's Lord, which requires both incarnation and divine identity to explain.</p>",
"45": "<p>'And in the hearing of all the people he said to his disciples, Beware of the scribes' — the public warning against scribes 'in the hearing of all the people' is a deliberate public act of prophetic denunciation. The explicit audience (all the people, the disciples) creates maximum public visibility for the indictment — this is not a private warning but a public honor-challenge to the scribal establishment. Jesus's willingness to issue public denunciations of the scribes while in the temple — their institutional home — demonstrates the boldness that has characterized the entire temple week.</p>",
"46": "<p>'Who like to walk around in long robes, and love greetings in the marketplaces and the best seats in the synagogues and the places of honor at feasts' — the four status-behaviors criticized (long robes, marketplace greetings, synagogue seats, feast places) are all honor-seeking behaviors in Greco-Roman and Jewish public culture. Long robes (stolai — formal robes worn by Roman officials and Jewish priestly-scribal figures) signaled high status. Marketplace greetings with proper titles (Rabbi, Abba, Teacher) were status performances. The best seat in the synagogue (facing the congregation from the front) and the honored couch at feasts were coveted positions of public visibility.</p>",
"47": "<p>'Who devour widows' houses and for a pretense make long prayers. They will receive the greater condemnation' — the two charges bracket each other: economic predation of the vulnerable (widows = the paradigmatic defenseless category in both Jewish and Greco-Roman law: Exod 22:22; Deut 10:18; Isa 1:17; Zech 7:10) combined with religious performance (long prayers as social performance rather than genuine petition). The condemnation (krima) they receive is not merely equal to their crimes but greater — their religious authority and knowledge amplifies their accountability (cf. Luke 12:47-48 on graduated judgment).</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'luke')
    merge_comm(existing, LUKE_CH19_20)
    save_comm('mkt-context', 'luke', existing)
    ch19 = len(existing.get('19', {}))
    ch20 = len(existing.get('20', {}))
    print(f'Luke 19: {ch19}/48 verses. Luke 20: {ch20}/47 verses.')

if __name__ == '__main__':
    main()
